function report = runAdaptiveResourcePreflight(options)
%RUNADAPTIVERESOURCEPREFLIGHT Forecast full-format adaptive CPU resources.
%
% The synthetic plan uses one exact initial local grid per tile and expands a
% deterministic fraction to a wider final grid. It allocates only the tile
% tables; no image or cost volume of TargetImageSize is materialized.
%
% Traceability: algo/main.tex Secs. 10.4 and 14.6; implementation plan C1
% milestone 6.

arguments
    options.TargetImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [5000, 15000]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
    options.InitialLabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.InitialLabelCount, 3)} = 7
    options.ExpandedLabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.ExpandedLabelCount, 3)} = 15
    options.ExpansionFraction (1, 1) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.ExpansionFraction, 0), mustBeLessThanOrEqual( ...
        options.ExpansionFraction, 1)} = 0.5
    options.Precision (1, 1) string ...
        {mustBeMember(options.Precision, ["single", "double"])} = "single"
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.IntegrationRadius (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 3
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 8
    options.GroupIdenticalBands (1, 1) logical = true
    options.MaximumBandTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.MaximumPendingTiles (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 14
    options.OverviewMaximumDimension (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 1600
    options.Decimation (1, 1) double ...
        {mustBeFinite, mustBeInteger, ...
        mustBeGreaterThanOrEqual(options.Decimation, 2)} = 2
    options.IncludeIntermediateLevels (1, 1) logical = false
    options.OutputProfile (1, 1) string ...
        {mustBeMember(options.OutputProfile, ...
        ["diagnostic", "compact"])} = "diagnostic"
    options.MemoryBudgetGiB (1, 1) double ...
        {mustBeFinite, mustBePositive} = 32
    options.DiskBudgetGiB (1, 1) double ...
        {mustBeFinite, mustBePositive} = 16
    options.RamSafetyFactor (1, 1) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.RamSafetyFactor, 1)} = 1.25
    options.DiskSafetyFactor (1, 1) double ...
        {mustBeFinite, mustBeGreaterThanOrEqual( ...
        options.DiskSafetyFactor, 1)} = 1.1
    options.MeasuredDensePixelLabelsPerSecond (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 27.5e6
    options.MeasuredSgmPixelLabelsPerSecond (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.768e6
    options.MeasuredFileIoMebibytesPerSecond (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 14.946
    options.RefuseUnsafe (1, 1) logical = false
    options.Verbose (1, 1) logical = true
end

[initialPlan, finalPlan, expanded] = makeForecastPlans( ...
    options.TargetImageSize, options.TileSize, ...
    options.InitialLabelCount, options.ExpandedLabelCount, ...
    options.ExpansionFraction);
factors = HeightImagePyramid.selectFactors( ...
    options.TargetImageSize, options.OverviewMaximumDimension, ...
    options.Decimation, IncludeIntermediateLevels= ...
    options.IncludeIntermediateLevels);
report = HeightSweepMemoryEstimator.estimateAdaptive( ...
    initialPlan, finalPlan, Precision=options.Precision, ...
    DirectionCount=options.DirectionCount, ...
    IntegrationRadius=options.IntegrationRadius, ...
    LabelBlockSize=options.LabelBlockSize, ...
    GroupIdenticalBands=options.GroupIdenticalBands, ...
    MaximumBandTiles=options.MaximumBandTiles, ...
    MaximumPendingTiles=options.MaximumPendingTiles, ...
    PyramidFactors=factors, OutputProfile=options.OutputProfile, ...
    MemoryBudgetGiB=options.MemoryBudgetGiB, ...
    DiskBudgetGiB=options.DiskBudgetGiB, ...
    RamSafetyFactor=options.RamSafetyFactor, ...
    DiskSafetyFactor=options.DiskSafetyFactor, ...
    MeasuredDensePixelLabelsPerSecond= ...
    options.MeasuredDensePixelLabelsPerSecond, ...
    MeasuredSgmPixelLabelsPerSecond= ...
    options.MeasuredSgmPixelLabelsPerSecond, ...
    MeasuredFileIoMebibytesPerSecond= ...
    options.MeasuredFileIoMebibytesPerSecond, ...
    RefuseUnsafe=options.RefuseUnsafe);
report.RequestedExpansionFraction = options.ExpansionFraction;
report.ActualExpansionFraction = nnz(expanded) ./ height(initialPlan);
report.TileSize = options.TileSize;
report.InitialLabelCount = options.InitialLabelCount;
report.ExpandedLabelCount = options.ExpandedLabelCount;
report.GroupIdenticalBands = options.GroupIdenticalBands;
report.MaximumBandTiles = options.MaximumBandTiles;
report.ForecastBasis = ...
    "C7 local CPU rates; retune on the Windows target before operational use";
report.AllocationPolicy = ...
    "tile-plan-only forecast; target images and volumes are not allocated";
if options.Verbose
    fprintf("Adaptive target: %d x %d, %d tiles, %.1f%% expanded, %s\n", ...
        options.TargetImageSize(1), options.TargetImageSize(2), ...
        height(initialPlan), 100 .* report.ActualExpansionFraction, ...
        options.OutputProfile);
    fprintf("  RAM %.3f / %.3f GiB; disk %.3f / %.3f GiB; safe %s\n", ...
        report.RequestedRamBytes ./ 2 ^ 30, options.MemoryBudgetGiB, ...
        report.RequestedDiskBytes ./ 2 ^ 30, options.DiskBudgetGiB, ...
        string(report.SafeToRun));
    fprintf("  dense %.1f s, SGM %.1f s, I/O %.1f s, total %.1f s\n", ...
        report.EstimatedDenseSeconds, report.EstimatedSgmSeconds, ...
        report.EstimatedIoSeconds, report.EstimatedTotalSeconds);
    disp(report.Components)
end
end

function [initialPlan, finalPlan, expanded] = makeForecastPlans( ...
        imageSize, tileSize, initialLabelCount, expandedLabelCount, ...
        expansionFraction)
rowStarts = 1:tileSize(1):imageSize(1);
columnStarts = 1:tileSize(2):imageSize(2);
tileCount = numel(rowStarts) .* numel(columnStarts);
z0 = linspace(-50, 50, initialLabelCount);
rows = cell(tileCount, 8);
tile = 0;
for rowStart = rowStarts
    for columnStart = columnStarts
        tile = tile + 1;
        rowEnd = min(rowStart + tileSize(1) - 1, imageSize(1));
        columnEnd = min( ...
            columnStart + tileSize(2) - 1, imageSize(2));
        rows(tile, :) = {tile, rowStart, rowEnd, columnStart, columnEnd, ...
            (rowEnd - rowStart + 1) .* (columnEnd - columnStart + 1), ...
            initialLabelCount, {z0}};
    end
end
initialPlan = cell2table(rows, VariableNames=["Tile", "RowStart", ...
    "RowEnd", "ColumnStart", "ColumnEnd", "PixelCount", "LabelCount", ...
    "HeightLabelsMetres"]);
finalPlan = initialPlan;
expanded = false(tileCount, 1);
count = round(expansionFraction .* tileCount);
if count > 0
    ids = unique(round(linspace(1, tileCount, count)));
    expanded(ids) = true;
    z1 = linspace(-100, 100, expandedLabelCount);
    finalPlan.LabelCount(expanded) = expandedLabelCount;
    finalPlan.HeightLabelsMetres(expanded) = repmat({z1}, nnz(expanded), 1);
end
end
